package com.mbeddr.mpsutil.ccmenu.runtime.chooser;

/*Generated by MPS */

import jetbrains.mps.openapi.editor.cells.SubstituteAction;

public class GroupUtil {

  public static String getGroupName(SubstituteAction action) {
    String descriptionText = action.getDescriptionText("");
    if (descriptionText == null) {
      return null;
    }
    if (descriptionText.startsWith("#") && descriptionText.contains(":")) {
      return descriptionText.substring(1, descriptionText.indexOf(":"));
    } else {
      return null;
    }
  }

  public static String getDescriptionText(SubstituteAction action, String pattern) {
    String descriptionText = action.getDescriptionText(pattern);
    if (descriptionText == null) {
      return null;
    }
    if (descriptionText.startsWith("#") && descriptionText.contains(":")) {
      descriptionText = descriptionText.substring(descriptionText.indexOf(":") + 1);
      return ((descriptionText == null ? null : descriptionText.trim()));
    } else {
      return descriptionText;
    }
  }

}
